using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.Native;
using GTA.UI;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private enum MissionState { None, Active, Success, Failed }

        private LiveStudioClient _client;
        private MissionState _state = MissionState.None;

        // Mission data
        private Vehicle _missionVehicle;
        private Vector3 _destination;
        private Blip _destinationBlip;
        private int _startTime;
        private const int TIME_LIMIT = 600; // 10 minutes in seconds
        private int _leaveVehicleStartTime = -1;
        private const int LEAVE_GRACE = 3;

        // Detour
        private Blip _detourBlip;
        private Vector3 _detourPosition;

        // Escort
        private List<Vehicle> _escortVehicles = new List<Vehicle>();
        private List<Ped> _escortPeds = new List<Ped>();
        private const int MAX_ESCORT = 2;
        private RelationshipGroup _escortGroup;

        // Pursuit
        private List<Vehicle> _pursuitVehicles = new List<Vehicle>();
        private List<Ped> _pursuitPeds = new List<Ped>();
        private const int MAX_PURSUIT = 3;
        private RelationshipGroup _pursuitGroup;

        // Cooldowns
        private Dictionary<string, int> _cooldowns = new Dictionary<string, int>();
        private static readonly Dictionary<string, int> CooldownDurations = new Dictionary<string, int>
        {
            {"start_delivery", 60000},
            {"repair", 5000},
            {"tire", 30000},
            {"clear", 10000},
            {"boost", 5000},
            {"escort", 15000},
            {"flat", 10000},
            {"stall", 15000},
            {"pursuit", 10000},
            {"slick", 10000},
            {"boom", 15000},
            {"detour", 20000}
        };

        // Temporary effects
        private bool _bulletproofActive;
        private int _bulletproofExpireTime;
        private bool _boostActive;
        private int _boostEndTime;
        private bool _stallActive;
        private int _stallExpireTime;
        private bool _slickActive;
        private int _slickExpireTime;

        private Random _random = new Random();

        public Mod()
        {
            // Initialize relationship groups
            _escortGroup = World.AddRelationshipGroup("DeliveryEscort");
            _pursuitGroup = World.AddRelationshipGroup("DeliveryPursuit");
            Game.Player.Character.RelationshipGroup.SetRelationship(_escortGroup, Relationship.Companion, true);
            Game.Player.Character.RelationshipGroup.SetRelationship(_pursuitGroup, Relationship.Hate, true);
            _escortGroup.SetRelationship(_pursuitGroup, Relationship.Hate, true);
            _pursuitGroup.SetRelationship(_escortGroup, Relationship.Hate, true);

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();

            Tick += OnTick;
            Aborted += OnAborted;
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();

            if (_state == MissionState.Active)
            {
                PerformFailureCheck();
                RestoreTemporaryEffects();
            }
        }

        private void OnAborted(object sender, EventArgs e)
        {
            CleanUpMission();
            _client?.Dispose();
        }

        private void HandleEvent(LiveStudioEvent liveEvent)
        {
            if (liveEvent is ChatEvent chat)
            {
                MainThreadDispatcher.Enqueue(() => ProcessChatCommand(chat.Content));
            }
        }

        private void ProcessChatCommand(string message)
        {
            if (string.IsNullOrWhiteSpace(message)) return;
            string cmd = message.Trim().ToLowerInvariant();

            switch (cmd)
            {
                case "!start_delivery":
                    if (CanTrigger("start_delivery"))
                        StartMission();
                    break;
                case "!repair":
                    if (_state == MissionState.Active && CanTrigger("repair"))
                        DoRepair();
                    break;
                case "!tire":
                    if (_state == MissionState.Active && CanTrigger("tire"))
                        DoBulletproofTires();
                    break;
                case "!clear":
                    if (_state == MissionState.Active && CanTrigger("clear"))
                        ClearPursuits();
                    break;
                case "!boost":
                    if (_state == MissionState.Active && CanTrigger("boost"))
                        DoBoost();
                    break;
                case "!escort":
                    if (_state == MissionState.Active && CanTrigger("escort"))
                        SpawnEscort();
                    break;
                case "!flat":
                    if (_state == MissionState.Active && CanTrigger("flat"))
                        DoFlatTires();
                    break;
                case "!stall":
                    if (_state == MissionState.Active && CanTrigger("stall"))
                        DoStall();
                    break;
                case "!pursuit":
                    if (_state == MissionState.Active && CanTrigger("pursuit"))
                        SpawnPursuit();
                    break;
                case "!slick":
                    if (_state == MissionState.Active && CanTrigger("slick"))
                        DoSlick();
                    break;
                case "!boom":
                    if (_state == MissionState.Active && CanTrigger("boom"))
                        DoBoom();
                    break;
                case "!detour":
                    if (_state == MissionState.Active && CanTrigger("detour"))
                        DoDetour();
                    break;
            }
        }

        private bool CanTrigger(string key)
        {
            int now = Game.GameTime;
            if (_cooldowns.TryGetValue(key, out int last) && (now - last) < CooldownDurations[key])
                return false;
            _cooldowns[key] = now;
            return true;
        }

        private void StartMission()
        {
            if (_state == MissionState.Active) return;

            Player player = Game.Player;
            if (!player.Character.IsInVehicle())
            {
                GTA.UI.Notification.Show("~r~您需要先进入一辆车!");
                return;
            }

            Vehicle veh = player.Character.CurrentVehicle;
            if (veh == null || veh.IsDead)
            {
                GTA.UI.Notification.Show("~r~当前车辆无效!");
                return;
            }

            _missionVehicle = veh;
            _startTime = Game.GameTime;
            _state = MissionState.Active;
            _leaveVehicleStartTime = -1;

            _destination = GetRandomRoadDestination(veh.Position, 3000f, 5000f);
            _destinationBlip = World.CreateBlip(_destination);
            _destinationBlip.Sprite = BlipSprite.Destination;
            _destinationBlip.Color = BlipColor.Yellow;
            _destinationBlip.Name = "Delivery Point";

            GTA.UI.Notification.Show("~g~任务开始! 10分钟内将车送达终点。");
            GTA.UI.Screen.ShowSubtitle("货物运送开始", 3000);
        }

        private Vector3 GetRandomRoadDestination(Vector3 origin, float minDist, float maxDist)
        {
            for (int i = 0; i < 20; i++)
            {
                float angle = (float)(_random.NextDouble() * Math.PI * 2);
                float distance = (float)(minDist + _random.NextDouble() * (maxDist - minDist));
                Vector3 target = origin + new Vector3((float)Math.Cos(angle) * distance,
                                                      (float)Math.Sin(angle) * distance,
                                                      0f);
                Vector3 safe = World.GetNextPositionOnStreet(target);
                if (safe != Vector3.Zero && World.GetDistance(origin, safe) >= minDist * 0.9f)
                    return safe;
                target = World.GetSafeCoordForPed(target);
                if (target != Vector3.Zero && World.GetDistance(origin, target) >= minDist * 0.9f)
                    return target;
            }
            Vector3 fallback = origin + new Vector3(4000f, 0f, 0f);
            fallback = World.GetSafeCoordForPed(fallback);
            return fallback == Vector3.Zero ? origin + new Vector3(4000f, 0f, 0f) : fallback;
        }

        private void PerformFailureCheck()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists() || _missionVehicle.IsDead)
            {
                EndMission(false, "车辆已毁!");
                return;
            }

            Player player = Game.Player;
            Vehicle currentVeh = player.Character.CurrentVehicle;
            bool driverPresent = currentVeh != null && currentVeh == _missionVehicle;

            if (!driverPresent)
            {
                if (_leaveVehicleStartTime == -1)
                    _leaveVehicleStartTime = Game.GameTime;
                else if ((Game.GameTime - _leaveVehicleStartTime) > LEAVE_GRACE * 1000)
                {
                    EndMission(false, "离开了任务车辆!");
                    return;
                }
            }
            else
            {
                _leaveVehicleStartTime = -1;
            }

            int elapsed = (Game.GameTime - _startTime) / 1000;
            if (elapsed >= TIME_LIMIT)
            {
                EndMission(false, "时间到!");
                return;
            }

            if (_detourBlip != null && _detourBlip.Exists() && _missionVehicle.Position.DistanceTo(_detourPosition) < 10f)
            {
                _detourBlip.Delete();
                _detourBlip = null;
                GTA.UI.Notification.Show("~g~额外检查点通过!");
            }

            if (_detourBlip == null && _missionVehicle.Position.DistanceTo(_destination) < 15f)
            {
                EndMission(true, "货物送达!");
            }
        }

        private void EndMission(bool success, string reason)
        {
            _state = success ? MissionState.Success : MissionState.Failed;
            CleanUpMission();
            if (success)
                GTA.UI.Notification.Show("~g~任务成功！货物已送达。");
            else
                GTA.UI.Notification.Show("~r~任务失败：" + reason);
        }

        private void CleanUpMission()
        {
            CleanEntityList(_escortVehicles, _escortPeds);
            CleanEntityList(_pursuitVehicles, _pursuitPeds);
            _escortVehicles.Clear();
            _escortPeds.Clear();
            _pursuitVehicles.Clear();
            _pursuitPeds.Clear();

            if (_destinationBlip != null && _destinationBlip.Exists())
                _destinationBlip.Delete();
            _destinationBlip = null;
            if (_detourBlip != null && _detourBlip.Exists())
                _detourBlip.Delete();
            _detourBlip = null;

            if (_missionVehicle != null && _missionVehicle.Exists())
            {
                if (_bulletproofActive)
                    SetBulletproof(_missionVehicle, false);
                if (_stallActive)
                    _missionVehicle.EngineRunning = true;
                if (_slickActive)
                    Function.Call(Hash.SET_VEHICLE_REDUCE_GRIP, _missionVehicle.Handle, false);
            }

            _missionVehicle = null;
            _state = MissionState.None;
            _bulletproofActive = false;
            _boostActive = false;
            _stallActive = false;
            _slickActive = false;
            _leaveVehicleStartTime = -1;
        }

        private void CleanEntityList(List<Vehicle> vehicles, List<Ped> peds)
        {
            foreach (Ped ped in peds)
            {
                if (ped != null && ped.Exists())
                    ped.Delete();
            }
            foreach (Vehicle veh in vehicles)
            {
                if (veh != null && veh.Exists())
                    veh.Delete();
            }
        }

        private void RestoreTemporaryEffects()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            int now = Game.GameTime;

            if (_bulletproofActive && now > _bulletproofExpireTime)
            {
                SetBulletproof(_missionVehicle, false);
                _bulletproofActive = false;
            }

            if (_boostActive && now > _boostEndTime)
            {
                _boostActive = false;
            }
            else if (_boostActive)
            {
                _missionVehicle.Velocity += _missionVehicle.ForwardVector * 1.5f;
            }

            if (_stallActive && now > _stallExpireTime)
            {
                _missionVehicle.EngineRunning = true;
                _stallActive = false;
            }

            if (_slickActive && now > _slickExpireTime)
            {
                Function.Call(Hash.SET_VEHICLE_REDUCE_GRIP, _missionVehicle.Handle, false);
                _slickActive = false;
            }
        }

        private void DoRepair()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            float maxHealth = _missionVehicle.MaxHealth;
            float current = _missionVehicle.Health;
            float newHealth = Math.Min(current + maxHealth * 0.25f, maxHealth);
            _missionVehicle.Health = newHealth;
            GTA.UI.Notification.Show("~g~车辆修复了25%!");
        }

        private void DoBulletproofTires()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_bulletproofActive) return;
            SetBulletproof(_missionVehicle, true);
            _bulletproofActive = true;
            _bulletproofExpireTime = Game.GameTime + 30000;
            GTA.UI.Notification.Show("~g~防爆轮胎 30 秒!");
        }

        private void SetBulletproof(Vehicle veh, bool state)
        {
            if (veh == null || !veh.Exists()) return;
            foreach (Wheel wheel in veh.Wheels)
            {
                wheel.BulletproofTires = state;
            }
        }

        private void ClearPursuits()
        {
            int count = _pursuitVehicles.Count;
            CleanEntityList(_pursuitVehicles, _pursuitPeds);
            _pursuitVehicles.Clear();
            _pursuitPeds.Clear();
            GTA.UI.Notification.Show("~g~清除了 " + count + " 辆追击车辆!");
        }

        private void DoBoost()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            _boostActive = true;
            _boostEndTime = Game.GameTime + 3000;
            GTA.UI.Notification.Show("~g~加速 3 秒!");
        }

        private void SpawnEscort()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_escortVehicles.Count >= MAX_ESCORT)
            {
                GTA.UI.Notification.Show("~r~护航车辆已满!");
                return;
            }

            Vector3 spawnPos = _missionVehicle.Position + _missionVehicle.ForwardVector * -10f + Vector3.WorldUp * 2f;
            Vehicle escortVeh = World.CreateVehicle(VehicleHash.Sultan, spawnPos, _missionVehicle.Heading);
            escortVeh.PlaceOnGround();
            Ped driver = escortVeh.CreatePedOnSeat(VehicleSeat.Driver, PedHash.Army01GMM);
            driver.RelationshipGroup = _escortGroup;
            driver.Weapons.Give(WeaponHash.CarbineRifle, 100, true, true);
            driver.Task.VehicleChase(_missionVehicle, 10f, VehicleDrivingFlags.Normal, 10f);
            driver.Task.FightAgainstHatedTargets(100f);

            _escortVehicles.Add(escortVeh);
            _escortPeds.Add(driver);
            GTA.UI.Notification.Show("~g~护航车辆已派出!");
        }

        private void DoFlatTires()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            Wheel[] wheels = _missionVehicle.Wheels;
            List<int> bustableIndices = new List<int>();
            for (int i = 0; i < wheels.Length; i++)
            {
                if (!wheels[i].BulletproofTires)
                    bustableIndices.Add(i);
            }
            if (bustableIndices.Count == 0)
            {
                GTA.UI.Notification.Show("~r~所有轮胎都是防爆的!");
                return;
            }
            int burstCount = Math.Min(2, bustableIndices.Count);
            for (int i = 0; i < burstCount; i++)
            {
                int idx = _random.Next(bustableIndices.Count);
                wheels[bustableIndices[idx]].Burst();
                bustableIndices.RemoveAt(idx);
            }
            GTA.UI.Notification.Show("~r~爆胎 " + burstCount + " 个!");
        }

        private void DoStall()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            _missionVehicle.EngineRunning = false;
            _stallActive = true;
            _stallExpireTime = Game.GameTime + 3000;
            GTA.UI.Notification.Show("~r~引擎熄火 3 秒!");
        }

        private void SpawnPursuit()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_pursuitVehicles.Count >= MAX_PURSUIT)
            {
                GTA.UI.Notification.Show("~r~追击车辆已满!");
                return;
            }

            Vector3 spawnPos = _missionVehicle.Position + _missionVehicle.ForwardVector * 20f + Vector3.WorldUp * 2f;
            Vehicle pursuitVeh = World.CreateVehicle(VehicleHash.SabreGT, spawnPos, _missionVehicle.Heading);
            pursuitVeh.PlaceOnGround();
            Ped driver = pursuitVeh.CreatePedOnSeat(VehicleSeat.Driver, PedHash.Runner01AMY);
            driver.RelationshipGroup = _pursuitGroup;
            driver.Task.VehicleChase(_missionVehicle, 10f, VehicleDrivingFlags.Aggressive, 10f);

            _pursuitVehicles.Add(pursuitVeh);
            _pursuitPeds.Add(driver);
            GTA.UI.Notification.Show("~r~追击车辆已派出!");
        }

        private void DoSlick()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            Function.Call(Hash.SET_VEHICLE_REDUCE_GRIP, _missionVehicle.Handle, true);
            _slickActive = true;
            _slickExpireTime = Game.GameTime + 8000;
            GTA.UI.Notification.Show("~r~降低抓地力 8 秒!");
        }

        private void DoBoom()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            float health = _missionVehicle.Health;
            Vector3 explosionPos = _missionVehicle.Position + _missionVehicle.RightVector * (_random.Next(2) == 0 ? 1 : -1) * 5f;
            World.AddExplosion(explosionPos, ExplosionType.Grenade, 0f, false, false, 0f);
            if (_missionVehicle.Exists() && !_missionVehicle.IsDead)
            {
                _missionVehicle.Health = Math.Max(1, health);
            }
            GTA.UI.Notification.Show("~r~附近爆炸!");
        }

        private void DoDetour()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_detourBlip != null)
            {
                GTA.UI.Notification.Show("~r~已存在额外检查点!");
                return;
            }

            Vector3 detourPos = GetRandomRoadDestination(_missionVehicle.Position, 500f, 1500f);
            _detourPosition = detourPos;
            _detourBlip = World.CreateBlip(detourPos);
            _detourBlip.Sprite = BlipSprite.RaceFinish;
            _detourBlip.Color = BlipColor.Red;
            GTA.UI.Notification.Show("~r~添加了绕路检查点!");
        }
    }
}
